import * as styles from "../styles/restaurant.module.css";
import React from "react";
import { Link } from "gatsby";
import SocialMediaIcon from "./icons";

const SUPPORTED_PLATFORMS = ["maps", "facebook", "twitter", "instagram"];

const isInternalLink = (url) => /^\/(?!\/)/.test(url);

const normalizeLinks = (data) => {
    return {
        maps: data.maps || data["map url"],
        facebook: data.facebook || data["social media"],
        twitter: data.twitter,
        instagram: data.instagram,
    };
};

const SocialMedia = ({ data }) => {

    const links = normalizeLinks(data);

    return (
        <div>
            {SUPPORTED_PLATFORMS
                .map((platform) => ({
                    platform,
                    link: links[platform],
                }))
                .filter(({ link }) => link)
                .map(({ platform, link }, index) =>
                    isInternalLink(link) ? (
                        <Link
                            key={index}
                            className={styles.restaurant_home_item}
                            to={link}
                        >
                            <SocialMediaIcon app={platform} />
                        </Link>
                    ) : (
                        <a
                            key={index}
                            className={styles.restaurant_home_item}
                            href={link}
                            target="_blank"
                            rel="noopener noreferrer"
                        >
                            <SocialMediaIcon app={platform} />
                        </a>
                    )
                )}
        </div>
    );
};

export default SocialMedia;
